
"use client";

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Instagram, Zap, Lock } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { ServiceCard, MakeupService } from '@/components/ServiceCard';
import { AIGeneratorDialog } from '@/components/AIGeneratorDialog';
import { cn } from "@/lib/utils";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

const categories = [
  {
    id: "all",
    name: "الكل - All",
    items: []
  },
  {
    id: "face",
    name: "الوجه - Face",
    items: ["Foundation", "Concealer", "Primer", "Setting Powder", "BB Cream"]
  },
  {
    id: "eyes",
    name: "العيون - Eyes",
    items: ["Eyeshadow Palettes", "Mascara", "Eyeliner", "Eyebrow Pens"]
  },
  {
    id: "lips",
    name: "الشفاه - Lips",
    items: ["Lipstick", "Lip Gloss", "Lip Liner", "Lip Balm"]
  },
  {
    id: "cheeks",
    name: "الخدود والإضاءة - Cheeks",
    items: ["Blush", "Highlighter", "Bronzer"]
  },
  {
    id: "tools",
    name: "الأدوات - Tools",
    items: ["Brushes Set", "Beauty Blenders", "Lashes", "Eyelash Curler"]
  }
];

export default function GirlsStore() {
  const { toast } = useToast();
  const [isSupervisor, setIsSupervisor] = useState(false);
  const [clickCount, setClickCount] = useState(0);
  const [selectedCategoryId, setSelectedCategoryId] = useState("all");
  
  // Password Protected States
  const [isPasswordDialogOpen, setIsPasswordDialogOpen] = useState(false);
  const [passwordInput, setPasswordInput] = useState("");

  const [services, setServices] = useState<(MakeupService & { categoryId?: string })[]>(() => [
    { 
      id: '1', 
      name: "Signature Gloss", 
      price: 45, 
      description: "High Shine & Deep Hydration for a flawless glow.", 
      imageUrl: "https://images.unsplash.com/photo-1522335789203-aabd1fc54bc9?q=80&w=600",
      categoryId: "lips"
    },
    { 
      id: '2', 
      name: "Velvet Matte", 
      price: 55, 
      description: "Intense pigment with a weightless comfortable finish.", 
      imageUrl: "https://images.unsplash.com/photo-1512496011212-323a784629c2?q=80&w=600",
      categoryId: "face"
    },
    { 
      id: '3', 
      name: "Glow Palette", 
      price: 65, 
      description: "Highlighter and bronzer for the ultimate summer radiance.", 
      imageUrl: "https://images.unsplash.com/photo-1522338242992-e1a54906a8da?q=80&w=600",
      categoryId: "cheeks"
    }
  ]);

  const handleAdminTrigger = () => {
    setClickCount(prev => prev + 1);
  };

  useEffect(() => {
    if (clickCount === 7) {
      if (isSupervisor) {
        setIsSupervisor(false);
        setClickCount(0);
        toast({
          title: "PUBLIC VIEW",
          description: "Returning to public shop.",
        });
      } else {
        setIsPasswordDialogOpen(true);
        setClickCount(0);
      }
    }
  }, [clickCount, isSupervisor, toast]);

  const handlePasswordSubmit = () => {
    if (passwordInput === "Hassan@GS#7") {
      setIsSupervisor(true);
      setIsPasswordDialogOpen(false);
      setPasswordInput("");
      toast({
        title: "ACCESS GRANTED",
        description: "Hassan Deeb Studio controls active.",
      });
    } else {
      toast({
        variant: "destructive",
        title: "ACCESS DENIED",
        description: "Incorrect password.",
      });
      setPasswordInput("");
    }
  };

  const addService = (name: string, description: string) => {
    const newService: MakeupService & { categoryId?: string } = {
      id: Date.now().toString(),
      name,
      price: 45,
      description,
      imageUrl: `https://picsum.photos/seed/${Date.now()}/800/800`,
      categoryId: selectedCategoryId === "all" ? "face" : selectedCategoryId
    };
    setServices([newService, ...services]);
  };

  const updateService = (updated: MakeupService) => {
    setServices(services.map(s => s.id === updated.id ? { ...updated, categoryId: (s as any).categoryId } : s));
  };

  const deleteService = (id: string) => {
    setServices(services.filter(s => s.id !== id));
  };

  const filteredServices = useMemo(() => {
    if (selectedCategoryId === "all") return services;
    return services.filter(s => s.categoryId === selectedCategoryId);
  }, [services, selectedCategoryId]);

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="pt-12 pb-6 px-6 text-center">
        <p className="text-[10px] tracking-[0.4em] text-pink-500/80 font-bold uppercase mb-4">
          POWERED BY HASSAN DEEB
        </p>
        <h1 
          onClick={handleAdminTrigger}
          className="font-display text-5xl md:text-7xl font-black uppercase leading-none tracking-tighter cursor-pointer select-none mb-6 text-pink-600 drop-shadow-sm transition-transform active:scale-95"
        >
          girls<br />store<span className="text-pink-400">.</span>
        </h1>

        {/* Categories Navigation */}
        <div className="flex overflow-x-auto pb-4 no-scrollbar gap-2 px-4 justify-start md:justify-center mt-4">
          {categories.map((cat) => (
            <button
              key={cat.id}
              onClick={() => setSelectedCategoryId(cat.id)}
              className={cn(
                "whitespace-nowrap px-6 py-2 rounded-full text-[10px] uppercase tracking-widest font-black transition-all border",
                selectedCategoryId === cat.id 
                  ? "bg-pink-500 text-white border-pink-500 shadow-lg scale-105" 
                  : "bg-white/50 text-pink-400 border-pink-100 hover:bg-white"
              )}
            >
              {cat.name}
            </button>
          ))}
        </div>
      </header>

      {/* Main Feed */}
      <main className="flex-grow max-w-2xl mx-auto px-6 py-8 w-full space-y-8">
        {isSupervisor && (
          <div className="glass p-8 rounded-[3rem] mb-12 flex flex-col items-center gap-6 border-pink-200 animate-in fade-in zoom-in duration-500">
            <div className="text-center">
              <h3 className="font-display text-xl uppercase font-black italic text-pink-700">Supervisor Active</h3>
              <p className="text-pink-500 text-[10px] uppercase tracking-widest mt-1">Manage store assets.</p>
            </div>
            <div className="flex gap-4">
              <AIGeneratorDialog onGenerated={addService} />
              <Button 
                onClick={() => addService("New Product", "Describe the product details...")}
                variant="outline"
                className="rounded-full bg-white/60 border-pink-200 text-[10px] uppercase tracking-widest h-12 px-8 text-pink-700 hover:bg-white"
              >
                <Plus className="w-4 h-4 mr-2" /> Manual Add
              </Button>
            </div>
          </div>
        )}

        <div className="space-y-8">
          {filteredServices.length > 0 ? (
            filteredServices.map(service => (
              <ServiceCard 
                key={service.id} 
                service={service} 
                isSupervisor={isSupervisor}
                onUpdate={updateService}
                onDelete={deleteService}
              />
            ))
          ) : (
            <div className="text-center py-20 glass rounded-[3rem]">
              <p className="text-pink-400 uppercase tracking-widest text-xs">No items in this category yet.</p>
            </div>
          )}

          {isSupervisor && (
            <div 
              onClick={() => addService("New Collection", "Details coming soon...")}
              className="aspect-square border-4 border-dashed border-pink-300 rounded-[3rem] flex flex-col items-center justify-center text-pink-400 hover:bg-white/50 transition-all cursor-pointer group"
            >
              <Plus size={48} strokeWidth={1} className="group-hover:scale-125 transition-transform" />
              <span className="text-[10px] uppercase tracking-[0.4em] mt-4 font-black">Add Collection</span>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="py-20 text-center">
        <p className="text-[11px] font-bold tracking-[0.2em] uppercase mb-8 text-pink-600">
          WHISH MONEY / OMT / CASH ON DELIVERY
        </p>
        
        <div className="flex justify-center gap-12 mb-12 text-pink-400">
          <Instagram size={28} className="hover:scale-110 hover:text-pink-600 transition-all cursor-pointer" />
          <Zap size={28} />
        </div>
        
        <p className="text-[9px] opacity-60 uppercase tracking-[0.5em] font-bold text-pink-900">
          © 2026 GIRLS STORE • BY HASSAN DEEB
        </p>
      </footer>

      {/* Password Dialog */}
      <Dialog open={isPasswordDialogOpen} onOpenChange={setIsPasswordDialogOpen}>
        <DialogContent className="sm:max-w-[400px] glass border-pink-200">
          <DialogHeader>
            <DialogTitle className="font-display text-xl uppercase text-pink-700">Studio Access</DialogTitle>
            <DialogDescription className="text-pink-500/70 uppercase text-[10px] tracking-widest">
              Please enter the supervisor password to manage store assets.
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="password" title="Password" />
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-pink-300" />
                <Input
                  id="password"
                  type="password"
                  placeholder="••••••••"
                  className="pl-10 h-12 bg-white/60 border-pink-100 rounded-2xl"
                  value={passwordInput}
                  onChange={(e) => setPasswordInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handlePasswordSubmit()}
                />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button 
              onClick={handlePasswordSubmit}
              className="w-full h-12 rounded-2xl bg-pink-500 hover:bg-pink-600 text-white font-black uppercase tracking-widest text-[10px]"
            >
              Verify Access
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
